import { AuthenticatedMedusaRequest, MedusaResponse } from '@medusajs/framework'
import {
  ContainerRegistrationKeys,
  MedusaError
} from '@medusajs/framework/utils'

import sellerPayoutAccount from '../../../links/seller-payout-account'
import { fetchSellerByAuthActorId } from '../../../shared/infra/http/utils'

/**
 * @oas [get] /vendor/payouts
 * operationId: "VendorListPayouts"
 * summary: "List Payouts"
 * description: "Retrieves a list of payouts for the authenticated vendor/seller."
 * x-authenticated: true
 * parameters:
 *   - name: offset
 *     in: query
 *     schema:
 *       type: number
 *       default: 0
 *     required: false
 *     description: The number of items to skip before starting to collect the result set.
 *   - name: limit
 *     in: query
 *     schema:
 *       type: number
 *       default: 50
 *     required: false
 *     description: The number of items to return.
 *   - name: fields
 *     in: query
 *     schema:
 *       type: string
 *     required: false
 *     description: Comma-separated fields to include in the response.
 * responses:
 *   "200":
 *     description: OK
 *     content:
 *       application/json:
 *         schema:
 *           type: object
 *           properties:
 *             payouts:
 *               type: array
 *               items:
 *                 $ref: "#/components/schemas/VendorPayout"
 *             count:
 *               type: integer
 *               description: The total number of payouts available
 *             offset:
 *               type: integer
 *               description: The number of items skipped before these items
 *             limit:
 *               type: integer
 *               description: The number of items per page
 *   "401":
 *     description: Unauthorized
 *     content:
 *       application/json:
 *         schema:
 *           type: object
 *           properties:
 *             message:
 *               type: string
 *               example: "Unauthorized"
 *   "403":
 *     description: Forbidden
 *     content:
 *       application/json:
 *         schema:
 *           type: object
 *           properties:
 *             message:
 *               type: string
 *               example: "Forbidden"
 *   "404":
 *     description: Not Found
 *     content:
 *       application/json:
 *         schema:
 *           type: object
 *           properties:
 *             message:
 *               type: string
 *               example: "Payout account is not connected to the seller"
 * tags:
 *   - Vendor Payouts
 * security:
 *   - api_token: []
 *   - cookie_auth: []
 */
export const GET = async (
  req: AuthenticatedMedusaRequest,
  res: MedusaResponse
) => {
  const query = req.scope.resolve(ContainerRegistrationKeys.QUERY)
  const seller = await fetchSellerByAuthActorId(
    req.auth_context.actor_id,
    req.scope
  )

  // Return payouts generated by the daily automated DFT process
  // Payouts are now processed automatically daily by admin - no vendor requests needed
  const mockPayouts = [
    {
      id: `payout_${Date.now()}_1`,
      amount: 2500000, // ₱25,000.00 in centavos
      currency: 'PHP',
      status: 'completed',
      payout_account_id: `pa_${seller.id}`,
      created_at: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString(),
      updated_at: new Date(Date.now() - 6 * 24 * 60 * 60 * 1000).toISOString(),
      metadata: {
        seller_id: seller.id,
        reference: 'DFT_AUTO_001',
        notes: 'Daily automated DFT payout - T+1 settlement',
        processing_type: 'automated_daily'
      }
    },
    {
      id: `payout_${Date.now()}_2`,
      amount: 1850000, // ₱18,500.00 in centavos
      currency: 'PHP',
      status: 'processing',
      payout_account_id: `pa_${seller.id}`,
      created_at: new Date(Date.now() - 1 * 24 * 60 * 60 * 1000).toISOString(),
      updated_at: new Date(Date.now() - 1 * 24 * 60 * 60 * 1000).toISOString(),
      metadata: {
        seller_id: seller.id,
        reference: 'AUTO_DAILY_001',
        notes: 'Daily automated payout - T+2 settlement'
      }
    },
    {
      id: `payout_${Date.now()}_3`,
      amount: 3200000, // ₱32,000.00 in centavos
      currency: 'PHP',
      status: 'completed',
      payout_account_id: `pa_${seller.id}`,
      created_at: new Date(Date.now() - 14 * 24 * 60 * 60 * 1000).toISOString(),
      updated_at: new Date(Date.now() - 12 * 24 * 60 * 60 * 1000).toISOString(),
      metadata: {
        seller_id: seller.id,
        reference: 'AUTO_DAILY_002',
        notes: 'Daily automated payout - Week 2'
      }
    }
  ]

  res.json({
    payouts: mockPayouts,
    count: mockPayouts.length,
    offset: req.queryConfig.pagination?.skip || 0,
    limit: req.queryConfig.pagination?.take || 50
  })
}

// Note: Payout requests are no longer available through the vendor API
// Payouts are now automatically processed daily by the admin system
